const profileRow = $input.first().json || {};
const brandData = profileRow.data_json || {};
const brandId = $('SUPABASE Get Config').first().json.brand_id || $('SET Input Params').first().json.brand_id;
const maxVideos = $('SET Input Params').first().json.max_videos;
const topK = $('SET Input Params').first().json.top_k;
const nDays = $('SET Input Params').first().json.n_days;

// Brand's active platforms from channels[] in brand_profiles.data_json
const channels = brandData.channels || brandData.tone_by_channel || [];
const activePlatforms = new Set(
  channels.map(c => (c.name || c.channel || '').toLowerCase().trim())
);

function getHandle(url, platform) {
  if (!url) return null;
  url = String(url).trim();
  if (platform === 'instagram') {
    const m = url.match(/instagram\.com\/?@?([^/?#\s]+)/i);
    return m ? m[1].replace(/\/$/, '') : null;
  }
  if (platform === 'tiktok') {
    const m = url.match(/tiktok\.com\/?@?([^/?#\s]+)/i);
    return m ? m[1].replace(/^@/, '').replace(/\/$/, '') : null;
  }
  if (platform === 'linkedin') return url.replace(/\/$/, '');
  if (platform === 'twitter') {
    const m = url.match(/(?:twitter|x)\.com\/?@?([^/?#\s]+)/i);
    return m ? m[1].replace(/\/$/, '') : null;
  }
  return null;
}

const companyName = (brandData.identity && brandData.identity.company_name) || 'the brand';
const industry = (brandData.identity && brandData.identity.industry) || 'B2B';

const analysisInstruction = brandData.analysis_instruction || '# CONCEPT\nOverall description (1-3 sentences).\n\n# HOOK\n- VISUAL: first 1-2 seconds\n- TEXT: on-screen text (max 8 words)\n- SPOKEN: first words said (quote it)\n- WHY IT WORKS: why this hook stops the viewer\n\n# RETENTION MECHANISMS\nHow the creator retains viewers.\n\n# REWARD\nValue the viewer gets.\n\n# SCRIPT\nFull content (1-20 sentences). THE SHORTER THE BETTER.';

const newConceptsInstruction = brandData.new_concepts_instruction || ('Adapt this content for ' + companyName + ' in the ' + industry + ' space.\n\nGive 3 NEW concepts inspired by the reference — do NOT copy, translate the core idea into the brand context. Focus sharply on the HOOKS.\n\n# CONCEPT 1\nDescription (1-3 sentences)\n\n## HOOK\n- VISUAL: First 2 seconds\n- SPOKEN: First line (quote it)\n- WHY IT WORKS: Why this hook stops the viewer\n\n## SCRIPT\nScene flow and spoken text (1-20 sentences)\n\n# CONCEPT 2\n...\n\n# CONCEPT 3\n...');

const competitors = brandData.competitors || [];
const jobs = [];

for (const comp of competitors) {
  const compName = comp.name || 'Unknown';
  if (activePlatforms.has('instagram') && comp.instagram_url) {
    const h = getHandle(comp.instagram_url, 'instagram');
    if (h) jobs.push({ competitor_name: compName, platform: 'instagram', handle: h });
  }
  if (activePlatforms.has('tiktok') && comp.tiktok_url) {
    const h = getHandle(comp.tiktok_url, 'tiktok');
    if (h) jobs.push({ competitor_name: compName, platform: 'tiktok', handle: h });
  }
  if (activePlatforms.has('linkedin') && comp.linkedin_url) {
    const h = getHandle(comp.linkedin_url, 'linkedin');
    if (h) jobs.push({ competitor_name: compName, platform: 'linkedin', handle: h });
  }
  const twUrl = comp.twitter_url || comp.x_url;
  if ((activePlatforms.has('twitter') || activePlatforms.has('x')) && twUrl) {
    const h = getHandle(twUrl, 'twitter');
    if (h) jobs.push({ competitor_name: compName, platform: 'twitter', handle: h });
  }
}

if (!jobs.length) return [{ json: { _no_jobs: true } }];

return jobs.map(j => ({ json: { ...j, brand_id: brandId, max_videos: maxVideos, top_k: topK, n_days: nDays, analysis_instruction: analysisInstruction, new_concepts_instruction: newConceptsInstruction } }));

const raw = $input.all();
const job = $('SPLIT Jobs Loop').first().json;
const topK = job.top_k || 3;
const nDays = job.n_days || 30;
const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - nDays);

const items = raw
  .map(i => i.json)
  .filter(v => v && !v.error)
  .filter(v => v.videoUrl || v.url)
  .filter(v => { const d = v.timestamp ? new Date(v.timestamp) : null; return !d || d >= cutoff; })
  .sort((a, b) => (b.videoPlayCount || 0) - (a.videoPlayCount || 0))
  .slice(0, topK);

if (!items.length) return [{ json: { _no_posts: true } }];

return items.map(v => ({ json: {
  link: v.url || (v.shortCode ? ('https://www.instagram.com/reel/' + v.shortCode + '/') : v.videoUrl),
  video_url: v.videoUrl || '',
  thumbnail: v.displayUrl || v.thumbnailUrl || '',
  competitor_name: job.competitor_name,
  platform: 'instagram',
  views: v.videoPlayCount || 0,
  likes: v.likesCount || 0,
  comments: v.commentsCount || 0,
  shares: 0,
  text: v.caption || '',
  date_posted: v.timestamp ? new Date(v.timestamp).toISOString().split('T')[0] : '',
  brand_id: job.brand_id,
  analysis_instruction: job.analysis_instruction,
  new_concepts_instruction: job.new_concepts_instruction,
  is_video: !!(v.videoUrl)
} }));

const raw = $input.all();
const job = $('SPLIT Jobs Loop').first().json;
const topK = job.top_k || 3;
const nDays = job.n_days || 30;
const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - nDays);

function nz(v) { return typeof v === 'number' ? v : (parseInt(v) || 0); }

const items = raw
  .map(i => i.json)
  .filter(v => v && (v.webVideoUrl || v.videoUrl || v.id))
  .filter(v => {
    const ts = v.createTimeISO || (v.createTime ? new Date(v.createTime * 1000).toISOString() : null);
    const d = ts ? new Date(ts) : null;
    return !d || d >= cutoff;
  })
  .sort((a, b) => {
    const aV = (a.stats || {}).playCount || a.playCount || 0;
    const bV = (b.stats || {}).playCount || b.playCount || 0;
    return bV - aV;
  })
  .slice(0, topK);

if (!items.length) return [{ json: { _no_posts: true } }];

return items.map(v => {
  const stats = v.stats || {};
  const ts = v.createTimeISO || (v.createTime ? new Date(v.createTime * 1000).toISOString() : '');
  return { json: {
    link: v.webVideoUrl || v.videoUrl || ('https://tiktok.com/@' + job.handle + '/video/' + v.id),
    video_url: v.videoUrl || v.downloadAddr || '',
    thumbnail: (Array.isArray(v.covers) ? v.covers[0] : '') || v.cover || '',
    competitor_name: job.competitor_name,
    platform: 'tiktok',
    views: nz(stats.playCount || v.playCount),
    likes: nz(stats.diggCount || v.diggCount),
    comments: nz(stats.commentCount || v.commentCount),
    shares: nz(stats.shareCount || v.shareCount),
    text: v.text || v.desc || '',
    date_posted: ts ? new Date(ts).toISOString().split('T')[0] : '',
    brand_id: job.brand_id,
    analysis_instruction: job.analysis_instruction,
    new_concepts_instruction: job.new_concepts_instruction,
    is_video: !!(v.videoUrl || v.downloadAddr)
  } };
});

const raw = $input.all();
const job = $('SPLIT Jobs Loop').first().json;
const topK = job.top_k || 3;
const nDays = job.n_days || 30;
const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - nDays);

function nz(v) { return typeof v === 'number' ? v : (parseInt(v) || 0); }
function isPost(p) { return p && (p.content != null || p.engagement != null || p.postedAt != null); }

const postItems = raw.map(i => i.json).filter(isPost);

const filtered = postItems.filter(p => {
  const ts = p.postedAt && (p.postedAt.date || (p.postedAt.timestamp ? new Date(p.postedAt.timestamp).toISOString() : null));
  if (!ts) return true;
  const d = new Date(ts);
  return isNaN(d.getTime()) || d >= cutoff;
});

if (!filtered.length) return [{ json: { _no_posts: true } }];

const scored = filtered
  .map(p => {
    const eng = p.engagement || {};
    const l = nz(eng.likes || eng.reactions_total);
    const c = nz(eng.comments);
    const s = nz(eng.shares || eng.reposts);
    return { ...p, _score: l + c * 2 + s * 3 };
  })
  .sort((a, b) => b._score - a._score)
  .slice(0, topK);

return scored.map(p => {
  const eng = p.engagement || {};
  const ts = p.postedAt && (p.postedAt.date || (p.postedAt.timestamp ? new Date(p.postedAt.timestamp).toISOString() : null));
  return { json: {
    link: p.linkedinUrl || p.url || '',
    video_url: '',
    thumbnail: '',
    competitor_name: job.competitor_name,
    platform: 'linkedin',
    views: 0,
    likes: nz(eng.likes || eng.reactions_total),
    comments: nz(eng.comments),
    shares: nz(eng.shares || eng.reposts),
    text: String(p.content || p.text || '').slice(0, 2000),
    date_posted: ts ? new Date(ts).toISOString().split('T')[0] : '',
    brand_id: job.brand_id,
    analysis_instruction: job.analysis_instruction,
    new_concepts_instruction: job.new_concepts_instruction,
    is_video: false
  } };
});

const raw = $input.all();
const job = $('SPLIT Jobs Loop').first().json;
const topK = job.top_k || 3;
const nDays = job.n_days || 30;
const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - nDays);

function nz(v) { return typeof v === 'number' ? v : (parseInt(v) || 0); }

const items = raw
  .map(i => i.json)
  .filter(t => t && (t.full_text || t.text))
  .filter(t => {
    const d = t.created_at ? new Date(t.created_at) : null;
    return !d || isNaN(d.getTime()) || d >= cutoff;
  })
  .sort((a, b) => {
    const aL = (a.public_metrics || {}).like_count || nz(a.favorite_count);
    const bL = (b.public_metrics || {}).like_count || nz(b.favorite_count);
    return bL - aL;
  })
  .slice(0, topK);

if (!items.length) return [{ json: { _no_posts: true } }];

return items.map(t => {
  const pm = t.public_metrics || {};
  const tweetId = t.id || t.id_str || '';
  return { json: {
    link: tweetId ? ('https://twitter.com/' + job.handle + '/status/' + tweetId) : (t.url || ''),
    video_url: '',
    thumbnail: '',
    competitor_name: job.competitor_name,
    platform: 'twitter',
    views: nz(pm.impression_count || t.views_count),
    likes: nz(pm.like_count || t.favorite_count),
    comments: nz(pm.reply_count || t.reply_count),
    shares: nz(pm.retweet_count || t.retweet_count),
    text: String(t.full_text || t.text || '').slice(0, 1000),
    date_posted: t.created_at ? new Date(t.created_at).toISOString().split('T')[0] : '',
    brand_id: job.brand_id,
    analysis_instruction: job.analysis_instruction,
    new_concepts_instruction: job.new_concepts_instruction,
    is_video: false
  } };
});

const binary = $input.first().binary;
const videoData = binary && binary.videoData;
if (!videoData) return [];

const mimeType = (videoData.mimeType || 'video/mp4').split(';')[0].trim();
const vid = $input.first().json;

return [{
  json: {
    mime_type: mimeType,
    link: vid.link,
    video_url: vid.video_url,
    thumbnail: vid.thumbnail,
    competitor_name: vid.competitor_name,
    platform: vid.platform,
    views: vid.views,
    likes: vid.likes,
    comments: vid.comments,
    shares: vid.shares || 0,
    text: vid.text || '',
    date_posted: vid.date_posted,
    brand_id: vid.brand_id,
    analysis_instruction: vid.analysis_instruction,
    new_concepts_instruction: vid.new_concepts_instruction
  },
  binary: { videoData: videoData }
}];

const post = $input.first().json;
const text = post.text || '';
const firstLine = text.split(/[.!?\n]/)[0].trim().slice(0, 200);
const platformLabel = { linkedin: 'LinkedIn', twitter: 'Twitter/X' }[post.platform] || post.platform;

const analysis = '**CONCEPT**\nHigh-engagement ' + platformLabel + ' post from ' + post.competitor_name + '.\n\n**HOOK**\n- VISUAL: Text post opening\n- SPOKEN: "' + firstLine + '"\n- WHY IT WORKS: Strong engagement — ' + post.likes + ' likes, ' + post.comments + ' comments\n\n**CONTENT**\n' + text.slice(0, 800);

return [{ json: {
  analysis,
  link: post.link,
  thumbnail: post.thumbnail || '',
  competitor_name: post.competitor_name,
  platform: post.platform,
  views: post.views,
  likes: post.likes,
  comments: post.comments,
  shares: post.shares || 0,
  date_posted: post.date_posted,
  brand_id: post.brand_id,
  new_concepts_instruction: post.new_concepts_instruction
} }];

const inputs = $input.all();

// Get metadata from whichever analysis path fired
let analysisItems = [];
try { analysisItems = $('SET Extract Video Analysis').all(); } catch(e) {}
if (!analysisItems.length) {
  try { analysisItems = $('CODE Build Text Analysis').all(); } catch(e) {}
}

return inputs.map((input, i) => {
  const claudeResponse = input.json;
  const meta = analysisItems[i] ? analysisItems[i].json : {};

  const conceptsText = claudeResponse.content && claudeResponse.content[0] && claudeResponse.content[0].text
    ? claudeResponse.content[0].text
    : '';

  return { json: {
    link: meta.link || '',
    thumbnail: meta.thumbnail || '',
    creator: meta.competitor_name || '',
    competitor_name: meta.competitor_name || '',
    platform: meta.platform || 'instagram',
    views: meta.views || 0,
    likes: meta.likes || 0,
    comments: meta.comments || 0,
    shares: meta.shares || 0,
    analysis: meta.analysis || '',
    new_concepts: conceptsText,
    date_posted: meta.date_posted || '',
    date_added: new Date().toISOString().split('T')[0],
    config_name: meta.brand_id || '',
    brand_id: meta.brand_id || '',
    starred: false
  } };
});
